class Solution:
    def countPrefixSuffixPairs(self, words: List[str]) -> int:
        count = 0
        n = len(words)
        for i in range(n):
            for j in range(i + 1, n):
                str1 = words[i]
                str2 = words[j]
                if str1 == str2[:len(str1)] and str1 == str2[-len(str1):]:
                    count += 1
        return count
